VALUES
  ('heelevel3-6e11b43e-moex-00052', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-114-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '甲為中華民國國籍人士，其與A國籍乙在A國辦理結婚登記。嗣後乙持A國結婚證書向我國駐 A國代表處申請驗證結婚證書及核發依親居留簽證。然而我國駐A國代表處卻認為，甲與乙在面 談時對於結婚重要事實陳述不一致，因此駁回乙之簽證申請。依司法實務之見解，下列敘述何者 正確？', '["甲得以自己名義提起課予義務訴訟，請求發給乙簽證", "乙不具有我國國籍，因此無法提起行政救濟", "甲得以自己名義，提起撤銷訴願及撤銷訴訟，以資救濟", "因為甲本身並非依法得申請簽證之當事人，因此無法提起行政救濟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00053', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-114-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '下列何種情形國家不負損害賠償責任？', '["甲國家公園管理機關因颱風警報，在所屬國家公園登山口公告禁止入山，乙因假期難得，仍冒 險登山而發生山難", "丙機關設立之公園鞦韆已經壞損，不堪使用，故在該鞦韆旁標示不得使用，丁仍讓其未成年之 子女戊使用，戊不幸拋飛而受有重傷", "主管機關平日未巡視公園樹木狀況，因強烈颱風來襲，致樹木倒塌壓傷路過之民眾", "土地登記機關因可歸責之事由，發生登記錯誤"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00054', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-114-3082b5f1', 'sub-heelevel3-6e11b43e-02', NULL, 'single_choice', '依司法實務見解，公共事業之設施穿越私有土地之地下，致逾越所有權人社會責任所應忍受範圍， 形成個人之特別犧牲時，下列敘述何者正確？', '["土地所有權人得請求需用土地人向主管機關申請徵收地上權", "所有權人之土地所有權並未受剝奪，故應忍受此一財產權社會義務的合法限制", "此屬財產權之違法侵害，當事人應請求除去侵害", "無法律則無徵收補償，若法律未有規定時，所有權人不得請求需用土地人向主管機關申請徵收"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "b5b55ac548cd", "answer_pdf_sha1": "940b0a4bb83c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "229", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
