  ('heelevel3-6e11b43e-moex-00059', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-113-3a7b2121', 'sub-heelevel3-6e11b43e-01', NULL, 'single_choice', '有關「傳統公共行政」、「新公共管理」與「新公共服務」三種治理模式與思潮，其協調機制分別 建立在下列何者為基礎？', '["權威、價格與政治", "權威、價格與網絡", "政治、價格與網絡", "權威、網絡與政治"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "303", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00060', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-113-3a7b2121', 'sub-heelevel3-6e11b43e-01', NULL, 'single_choice', '下列何者為推動民營化的主要立論依據？', '["增加事業的自主權", "紓解通貨膨脹壓力", "免除政府業務監督的責任", "擴大政府預算規模"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "303", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('heelevel3-6e11b43e-moex-00061', 'heelevel3-6e11b43e', 'heelevel3-6e11b43e-moex-113-3a7b2121', 'sub-heelevel3-6e11b43e-01', NULL, 'single_choice', '考試委員在院會上爭論公務人員應該具備什麼特質，看起來應該是什麼樣子的公僕，考試委員的 爭論反映那個倫理學說？', '["亞里斯多德（Aristotle）的德行論", "羅斯（W.D.Ross）的直覺論", "彌勒（J.S.Mill）的行為效益論", "康德（I.Kant）的義務論"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:22+00:00", "source_pdf_sha1": "3c5fbab47917", "answer_pdf_sha1": "ea9f06b2527a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "303", "s": "0303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "原住民族行政"}'::jsonb, NULL)
